#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, Q;
        scanf("%d %d %d", &N, &M, &Q);
        int D[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &D[i]);
        }
        while (Q--) {
            int L, R;
            scanf("%d %d", &L, &R);
            int min_len = -1;
            for (int len = 1; len <= R - L + 1; len++) {
                for (int i = L - 1; i <= R - len; i++) {
                    int xor = 0;
                    for (int j = i; j < i + len; j++) {
                        xor ^= D[j];
                    }
                    if (xor >= M) {
                        if (min_len == -1 || len < min_len) {
                            min_len = len;
                        }
                    }
                }
            }
            printf("%d\n", min_len);
        }
    }
    return 0;
}

