        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int Q = sc.nextInt();
            int[] D = new int[N];
            for (int i = 0; i < N; i++) {
                D[i] = sc.nextInt();
            }
            while (Q-- > 0) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int min_len = -1;
                for (int len = 1; len <= R - L + 1; len++) {
                    for (int i = L - 1; i <= R - len; i++) {
                        int xor = 0;
                        for (int j = i; j < i + len; j++) {
                            xor ^= D[j];
                        }
                        if (xor >= M) {
